"""Filler-token insertion mechanism.

Filler is semantically-empty text placed BEFORE the answer position to give the model extra
forward-pass positions for hidden computation (Redwood 2026; Pfau et al. 2024).

Filler types:
- "counting":  "1 2 3 ... m"   (mirrors Redwood)
- "dots":      ". . . ."        (m dots, space-separated)
- "repeat_problem": repeats the problem statement m times (a third alternative)

`size` is the number of filler ITEMS (numbers / dots / repeats). The realized Anthropic token
count is measured empirically at runtime via the API `input_tokens` delta (see harness/run script);
tiktoken is only a rough cross-check (wrong tokenizer). We keep a documented size->token mapping in
the write-up. As a rough guide (measured on Opus 4.5): counting size ~150 -> ~300 input tokens.
"""


def make_filler(filler_type: str, size: int, problem_text: str | None = None) -> str:
    """Return the filler STRING for the given type and size (number of items)."""
    if size <= 0:
        return ""
    if filler_type == "counting":
        return " ".join(str(i) for i in range(1, size + 1))
    if filler_type == "dots":
        return " ".join("." for _ in range(size))
    if filler_type == "repeat_problem":
        if not problem_text:
            raise ValueError("repeat_problem filler requires problem_text")
        return " ".join(problem_text for _ in range(size))
    raise ValueError(f"Unknown filler_type {filler_type!r}")


def approx_counting_size_for_tokens(target_tokens: int) -> int:
    """Rough inverse: how many counting items to hit ~target_tokens (Opus tokenizer).

    Empirically ~2.04 tokens per counting item near size 180 (delta 367 tokens). Used only to pick
    starting sizes; the realized token count is always measured via the API input_tokens delta.
    """
    return max(1, round(target_tokens / 2.04))


FILLER_TYPES = ["counting", "dots", "repeat_problem"]

"""Segment 7 — shared analysis helpers (fast; reads JSONL, no API calls).

The Segment-7 main run streams to results/seg7_<level>_k<k>_<cond>.jsonl (iid) +
results/seg7_sumprod_fixed_{after,before}.jsonl (fixed-item arm). This module loads those cells and
implements the pre-registered position-resolved + cluster-bootstrap machinery used for the guard
checks and the descriptive per-cell sanity summary (the §5 verdict is Segment 8, NOT here).

Precision-safe: `correct`/`correct_robust` were computed with Python ints at the source; we never
re-compare big-int answers as floats. Robust scoring (`correct_robust`) is used for sumprod (and any
multiplication); first-integer (`correct`) for addition (per the locked scorers).
"""
import glob
import json
import math
import re
from collections import defaultdict

import numpy as np

ROBUST_FAMILIES = {"sumprod", "multiplication"}

# ---- locked grid constants (single source of truth; mirror results/preregistration.md §4) ----
# Level tag -> the canonical Segment-7 file stem (TAG used in run_segment7.sh).
LEVEL_TAG = {"sumprod_t3_d2": "sumprod", "add_n15_d6": "d6"}
LEVELS = ["sumprod_t3_d2", "add_n15_d6"]
# counting filler on Opus = exactly 2 realized tokens / item (verified from the input_tokens delta), so
# the pre-registered TOKEN n-grids map to ITEM sizes = tok/2. reveal-after item grids per k:
AFTER_SIZES = {1: [0, 12, 25, 50, 75, 100, 150, 200], 2: [0, 25, 50, 100], 4: [0, 50, 100, 200],
               8: [0, 100, 200]}
BEFORE_SIZES = {2: [0, 50], 4: [0, 100], 8: [0, 100]}
OP_SIZE = {2: 50, 4: 100, 8: 100}        # operating-point filler ITEMS per k (=100/200/200 tok)


def fpath(level, k, cond, design="iid"):
    """Canonical Segment-7 result path. cond in {reveal_after, reveal_before}; design in {iid, fixed_item}."""
    suf = "after" if cond == "reveal_after" else "before"
    if design == "fixed_item":
        return f"results/seg7_{LEVEL_TAG[level]}_fixed_{suf}.jsonl"
    return f"results/seg7_{LEVEL_TAG[level]}_k{k}_{suf}.jsonl"


def hald_logit_boost(p_n, n_n, p_0, n_0):
    """Haldane-continuity logit boost = logit(p_n) - logit(p_0) with +0.5 added to each correct/incorrect
    count (so it is defined at boundary accuracies). Used for the guard-#2 ceiling cells + descriptive
    logit reporting (Segment 8 does the formal logit-scale classification)."""
    def hl(p, n):
        c = p * n
        return math.log((c + 0.5) / (n - c + 0.5))
    return hl(p_n, n_n) - hl(p_0, n_0)


def eff(r):
    """Effective correctness under the locked scorer (robust for sumprod/mul, first-int else)."""
    return 1.0 if (r.get("correct_robust") if r["family"] in ROBUST_FAMILIES else r["correct"]) else 0.0


def load(path):
    meta, rows = None, []
    for line in open(path):
        line = line.strip()
        if not line:
            continue
        d = json.loads(line)
        if d.get("_meta"):
            meta = meta or d
            continue
        rows.append(d)
    return meta, rows


def early_labels(k):
    """Pre-registered early-position pool = first ceil(k/2) listed positions (1-indexed labels)."""
    return set(range(1, math.ceil(k / 2) + 1))


# --------------------------------------------------------------------------------------------------
# cluster bootstrap over drawn instances (the pre-registered inference unit, seed 0)
# --------------------------------------------------------------------------------------------------
def cluster_boot(clusters, seed=0, nb=4000):
    """95% percentile CI for the mean of all values, resampling the INSTANCE clusters (list of
    np.arrays, one per drawn instance). Returns (mean, lo, hi, n_rows, n_clusters)."""
    arrs = [np.asarray(c, float) for c in clusters if len(c)]
    if not arrs:
        return float("nan"), float("nan"), float("nan"), 0, 0
    flat = np.concatenate(arrs)
    nclu = len(arrs)
    rng = np.random.default_rng(seed)
    if nclu > 1:
        bs = np.array([np.concatenate([arrs[j] for j in rng.integers(0, nclu, nclu)]).mean()
                       for _ in range(nb)])
    else:
        # Degenerate-input guard ONLY (a single instance cluster): fall back to a row bootstrap so a CI
        # is still defined. Never triggers on real cells (every cell has >=1000 instance clusters; the
        # per-position views have nclu = #instances) -> NOT the pre-reg 'no data-dependent fallback'
        # concern, just a safety net for degenerate callers.
        bs = flat[rng.integers(0, len(flat), (nb, len(flat)))].mean(1)
    return float(flat.mean()), float(np.percentile(bs, 2.5)), float(np.percentile(bs, 97.5)), len(flat), nclu


def paired_diff_boot(clusters_a, clusters_b, seed=0, nb=4000):
    """Cluster bootstrap of (mean_b - mean_a) where a,b are dicts {inst: np.array} sharing instance
    keys (paired). Resamples the SHARED instance set jointly so the contrast SE captures covariance.
    Returns (diff_mean, lo, hi)."""
    insts = sorted(set(clusters_a) & set(clusters_b))
    if not insts:
        return float("nan"), float("nan"), float("nan")
    a_arr = [np.asarray(clusters_a[i], float) for i in insts]
    b_arr = [np.asarray(clusters_b[i], float) for i in insts]
    ma = np.concatenate(a_arr).mean()
    mb = np.concatenate(b_arr).mean()
    rng = np.random.default_rng(seed)
    nclu = len(insts)
    diffs = []
    for _ in range(nb):
        idx = rng.integers(0, nclu, nclu)
        va = np.concatenate([a_arr[j] for j in idx]).mean()
        vb = np.concatenate([b_arr[j] for j in idx]).mean()
        diffs.append(vb - va)
    diffs = np.array(diffs)
    return float(mb - ma), float(np.percentile(diffs, 2.5)), float(np.percentile(diffs, 97.5))


# --------------------------------------------------------------------------------------------------
# per-cell extraction: paired boosts by position / early-pool / Q1, clustered by instance
# --------------------------------------------------------------------------------------------------
def boost_by_inst(rows, k, size, *, pool="early", inst_min=0):
    """Return {inst: [paired boosts]} for the requested position pool at filler `size` (items) vs 0.
    Scoring is the locked per-family scorer via `eff` (robust for sumprod, first-int for addition).

    pool: 'early' (first ceil(k/2) labels), 'q1' (label 1), 'agg' (all labels), or an int label.
    """
    cells = defaultdict(dict)  # (inst, label) -> {size: eff}
    for r in rows:
        if r["k"] != k or r["inst"] < inst_min:
            continue
        cells[(r["inst"], r["reveal_label"])][r["filler_items"]] = eff(r)
    if pool == "early":
        keep = early_labels(k)
    elif pool == "q1":
        keep = {1}
    elif pool == "agg":
        keep = None
    elif isinstance(pool, int):
        keep = {pool}
    else:
        raise ValueError(pool)
    by_inst = defaultdict(list)
    for (inst, lab), sm in cells.items():
        if keep is not None and lab not in keep:
            continue
        if 0 in sm and size in sm:
            by_inst[inst].append(sm[size] - sm[0])
    return dict(by_inst)


def realized_tokens(rows, k, size):
    """Mean input_tokens(size) - mean input_tokens(0) over the cell (the measured filler-token delta)."""
    s0 = [r["input_tokens"] for r in rows if r["k"] == k and r["filler_items"] == 0]
    sn = [r["input_tokens"] for r in rows if r["k"] == k and r["filler_items"] == size]
    if not s0 or not sn:
        return float("nan")
    return float(np.mean(sn) - np.mean(s0))


def n0_by_position(rows, k):
    """n=0 accuracy per revealed position label -> {label: (acc, n)} (off-ceiling guard input)."""
    by = defaultdict(list)
    for r in rows:
        if r["k"] == k and r["filler_items"] == 0:
            by[r["reveal_label"]].append(eff(r))
    return {lab: (float(np.mean(v)), len(v)) for lab, v in sorted(by.items())}


def acc_by_position(rows, k, size):
    """n=size accuracy per revealed position label -> {label: (acc, n)}."""
    by = defaultdict(list)
    for r in rows:
        if r["k"] == k and r["filler_items"] == size:
            by[r["reveal_label"]].append(eff(r))
    return {lab: (float(np.mean(v)), len(v)) for lab, v in sorted(by.items())}


# --------------------------------------------------------------------------------------------------
# no-CoT integrity (guard #3) + show-work monitoring (guard #4)
# --------------------------------------------------------------------------------------------------
_DIGIT = re.compile(r"\d")
_LETTER = re.compile(r"[A-Za-z]")
_OP = re.compile(r"\d\s*[*×x=]\s*\d|\d\s*\+\s*\d")  # operator between digits (restated expr / partial sums)
_INT4 = re.compile(r"\d{4,}")


def operands_of(question):
    return {int(x) for x in re.findall(r"\d+", question or "")}


def genuine_violation(r):
    """Pre-reg guard #3 GENUINE no-CoT violation: the first parsed integer is an OPERAND of the
    revealed question (digit-initial show-work / restate-then-compute). Matches
    analyze_nocot_kquestion.genuine_violation."""
    p = r.get("parsed")
    return p is not None and p in operands_of(r.get("revealed_question", ""))


def broad_cot_flag(r):
    """BROAD visible-CoT-ish detector (superset of genuine_violation; mirrors
    analyze_nocot_kquestion.leak_reason): a populated reasoning field, letters before the first digit,
    an arithmetic operator between digits (restated expression / partial sums), >1 distinct ≥4-digit
    integer (restated operands / partial sums / answer-then-recalculate), output_tokens>14, truncation,
    or a genuine_violation. NB this is an UPPER bound that also catches benign 'answer-first then chatty
    epilogue' (e.g. integer then a `(Note: ...)`), which preserve no-CoT — so it OVER-counts. ALL such
    rows are scored WRONG or are genuinely answer-first; reported as a transparency upper bound."""
    raw = (r.get("raw_output") or "").strip()
    if r.get("reasoning") or r.get("reasoning_content"):
        return True
    m = _DIGIT.search(raw)
    if m and _LETTER.search(raw[:m.start()]):
        return True
    if _OP.search(raw):
        return True
    if len({s for s in _INT4.findall(raw)}) > 1:
        return True
    if r.get("output_tokens", 0) > 14:
        return True
    if r.get("truncated"):
        return True
    return genuine_violation(r)


def nocot_flags(rows):
    n = len(rows)
    if n == 0:
        return dict(n=0, trunc_pct=0.0, reason_pct=0.0, leak_pct=0.0, viol_pct=0.0, broad_pct=0.0)
    trunc = sum(1 for r in rows if r.get("truncated"))
    reason = sum(1 for r in rows if r.get("reasoning") or r.get("reasoning_content"))
    leak = viol = broad = 0
    for r in rows:
        t = (r.get("raw_output") or "").strip()
        m = _DIGIT.search(t)
        if m and _LETTER.search(t[:m.start()]):
            leak += 1
        if genuine_violation(r):
            viol += 1
        if broad_cot_flag(r):
            broad += 1
    return dict(n=n, trunc_pct=100 * trunc / n, reason_pct=100 * reason / n,
                leak_pct=100 * leak / n, viol_pct=100 * viol / n, broad_pct=100 * broad / n)


def nocot_by_size(rows, k):
    """Guard #3 per-SIZE (not pooled): {size: nocot_flags} for cell k. Lets us confirm <1% genuine
    violation at EACH n, per the §6 'per cell' requirement (vs a pooled-over-sizes rate)."""
    return {size: nocot_flags([r for r in rows if r["k"] == k and r["filler_items"] == size])
            for size in sorted({r["filler_items"] for r in rows if r["k"] == k})}


def showwork_rate(rows, k=None, size=None, label=None):
    """Guard #4 MONITORING (spaced-digit ANSWER format): fraction of rows where the conservative parse
    != robust parse — i.e. a benign spaced-digit ANSWER (' 2 9 4 5'->2945) that the robust scorer
    REASSEMBLES correctly (so it does NOT bias the robust-scored B_k/contrast; it only flags the
    output FORMAT). The scoring-biasing show-work pattern (restate-then-compute, first int = operand,
    scored WRONG even by robust) is the `genuine_violation` rate instead (see `genuine_viol_rate`)."""
    sub = [r for r in rows if (k is None or r["k"] == k) and (size is None or r["filler_items"] == size)
           and (label is None or r["reveal_label"] == label)]
    if not sub:
        return float("nan"), 0
    sw = sum(1 for r in sub if r.get("parsed") != r.get("parsed_robust"))
    return sw / len(sub), len(sub)


def genuine_viol_rate(rows, k=None, size=None):
    """The fraction of rows that are genuine no-CoT violations (first int = an operand -> scored WRONG).
    This is the show-work pattern that ACTUALLY biases scoring; guard #4 compares it before vs after
    (a before/after asymmetry could shift the contrast). Reported by (size, condition)."""
    sub = [r for r in rows if (k is None or r["k"] == k) and (size is None or r["filler_items"] == size)]
    if not sub:
        return float("nan"), 0
    return sum(1 for r in sub if genuine_violation(r)) / len(sub), len(sub)


# --------------------------------------------------------------------------------------------------
# fresh-vs-reused split (the §5.7 design firewall): design max inst per (level,k,cond,design,size)
# --------------------------------------------------------------------------------------------------
def design_max_inst_map():
    """Scan all PRE-Segment-7 design k-question result files (`results/kq_*.jsonl`; the Segment-7 run
    files are `results/seg7_*.jsonl`, so they are NOT matched by this glob and are correctly excluded);
    return {(level,k,condition,design,size): max_inst_seen} = the largest instance index run during the
    design (Segments 0–6) for that exact cell. Used to label Segment-7 draws fresh (inst > design max)
    vs reused. Only Opus rows are considered (the experiment model)."""
    out = defaultdict(lambda: -1)
    for f in sorted(glob.glob("results/kq_*.jsonl")):
        try:
            _, rows = load(f)
        except FileNotFoundError:
            continue
        for r in rows:
            if not str(r.get("model", "")).startswith("claude-opus"):
                continue
            key = (r["level"], r["k"], r["condition"], r.get("design", "iid"), r["filler_items"])
            if r["inst"] > out[key]:
                out[key] = r["inst"]
    return dict(out)


def design_max_inst_anysize(dmax_map, level, k, condition, design="iid"):
    """CONSERVATIVE 'ever-seen' design max inst over ANY size (for the §5.7 firewall: an instance drawn
    at any filler size during Segments 0–6 is 'seen'). `design_max_inst_map` keys on (..., size), so an
    instance reused at a DIFFERENT size isn't counted as 'seen' at this size — this collapses over size
    to give the stricter firewall cutoff Segment 8 should use."""
    return max([v for (lv, kk, c, d, s), v in dmax_map.items()
                if lv == level and kk == k and c == condition and d == design] + [-1])


def fresh_split(rows, level, k, condition, size, design="iid", dmax_map=None):
    """For one Segment-7 cell, return (n_reused, n_fresh, design_max) over DISTINCT instances at this
    (level,k,condition,size). Fresh = inst > design_max (never drawn in Segments 0–6)."""
    if dmax_map is None:
        dmax_map = design_max_inst_map()
    dmax = dmax_map.get((level, k, condition, design, size), -1)
    insts = sorted({r["inst"] for r in rows if r["k"] == k and r["condition"] == condition
                    and r["filler_items"] == size and r.get("design", "iid") == design
                    and r["level"] == level})
    reused = sum(1 for i in insts if i <= dmax)
    fresh = sum(1 for i in insts if i > dmax)
    return reused, fresh, dmax

